.darma-loader-darma-custom-372 {color: var(--loader-color, #f97316);
  --loader-secondary-color: var(--loader-secondary-color, #facc15);
  --loader-bg: var(--loader-bg, #ffffff);
  width: 60px;
  aspect-ratio: 1;
  display: grid;
}.darma-loader-darma-custom-372:before,.darma-loader-darma-custom-372:after {content: "";
  grid-area: 1/1;
  color:var(--loader-color, #f97316);
  animation: darma-loader-darma-custom-372-l19 1.5s infinite linear;
}.darma-loader-darma-custom-372:before {margin: 5px 20px;
  background: currentColor;
}.darma-loader-darma-custom-372:after {border: solid;
  border-width: 5px 20px;
  --s:0;
}@keyframes darma-loader-darma-custom-372-l19 {0% {transform: perspective(100px) rotate3d(1,var(--s,1),0,0) }25% {transform: perspective(100px) rotate3d(1,var(--s,1),0,90deg) }25.01% {transform: perspective(100px) rotate3d(1,var(--s,1),0,90deg) }40%,60% {transform: perspective(100px) rotate3d(1,var(--s,1),0,180deg)}75% {transform: perspective(100px) rotate3d(1,var(--s,1),0,270deg)}75.01% {transform: perspective(100px) rotate3d(1,var(--s,1),0,270deg)}90%,100%{transform: perspective(100px) rotate3d(1,var(--s,1),0,360deg)}}

